// Pin the shared table view so both runs reference the *same* expression.
let table = self_.get_iommu_table_by_ioid(ioid).unwrap();
let in_dom = table.mapping_4k().dom().contains(va);

// Pull the original function's ensures into the proof context for r1.
assert(in_dom == r1.is_Some());
assert(r1.is_Some() ==> table.mapping_4k().dom().contains(va)
    && table.mapping_4k()[va] == page_entry_to_map_entry(&r1.unwrap()));

// Same for r2 — same `table` instance, so the triggers line up.
assert(in_dom == r2.is_Some());
assert(r2.is_Some() ==> table.mapping_4k().dom().contains(va)
    && table.mapping_4k()[va] == page_entry_to_map_entry(&r2.unwrap()));

// Option shape agrees: both `is_Some` flags equal the single `in_dom`.
assert(r1.is_Some() == r2.is_Some());
assert(r1.is_None() == r2.is_None());

// On the Some branch, the map-projection of each payload is forced to
// equal `table.mapping_4k()[va]`, hence equal to each other.
if r1.is_Some() {
    assert(r2.is_Some());
    assert(table.mapping_4k().dom().contains(va));
    assert(table.mapping_4k()[va] == page_entry_to_map_entry(&r1.unwrap()));
    assert(table.mapping_4k()[va] == page_entry_to_map_entry(&r2.unwrap()));
    assert(page_entry_to_map_entry(&r1.unwrap())
        == page_entry_to_map_entry(&r2.unwrap()));
}
